from typing import List

def solve(nums: List[int], k: int) -> int:
    n = len(nums)
    max_so_far = nums[0]
    min_so_far = nums[-1]

    for i in range(n):
        if nums[i] > max_so_far:
            max_so_far = nums[i]
        if nums[i] < min_so_far:
            min_so_far = nums[i]
        unstable_value = max_so_far - min_so_far
        if unstable_value <= k:
            return i
    return -1
